/*
Rev-N-Rip Popup + Form Controller (Vault Theme Compact Patch V8) (Vault Theme Compact Patch)
- Loads the mailing list popup on every page.
- Uses images/revnrip_logo_transparent.png
- Has X close button and Not now button.
- If Formspree is not connected, it opens a pre-filled email fallback.
*/

(function () {
  if (window.__REVNRIP_SITE_CONTROLLER_V8__) return;
  window.__REVNRIP_SITE_CONTROLLER_V8__ = true;

  const EMAIL_TO = "Info.revnrip@gmail.com";
  const FORM_ENDPOINT = "https://formspree.io/f/YOUR_FORMSPREE_FORM_ID";
  const LOGO_SRC = "./images/revnrip_logo_transparent.png";
  const POPUP_THEME_IMG = "data:image/png;base64,";
  const POPUP_SESSION_KEY = "revnrip_popup_seen_v8";

  function isFormspreeConnected(action) {
    return action && action.includes("formspree.io/f/") && !action.includes("YOUR_FORMSPREE_FORM_ID");
  }

  function getFormLabel(form) {
    const hiddenType = form.querySelector('input[name="form_type"]')?.value;
    const subject = form.querySelector('input[name="_subject"]')?.value;
    if (hiddenType) return hiddenType;
    if (subject) return subject;
    if (form.id && form.id.toLowerCase().includes("popup")) return "Mailing List / Giveaway Signup";
    return "Rev-N-Rip Website Inquiry";
  }

  function formToText(form) {
    const data = new FormData(form);
    const lines = [];
    lines.push("Rev-N-Rip Website Submission");
    lines.push("Form Type: " + getFormLabel(form));
    lines.push("");
    for (const [key, value] of data.entries()) {
      if (value instanceof File) {
        if (value.name) lines.push(`${key}: ${value.name} (attach this file/photo manually if needed)`);
        continue;
      }
      if (key.startsWith("_") || key === "send_to" || key === "recipient") continue;
      lines.push(`${key}: ${value || "(blank)"}`);
    }
    lines.push("");
    lines.push("Generated from the Rev-N-Rip website.");
    return lines.join("\n");
  }

  function openMailFallback(form) {
    const subject = encodeURIComponent(getFormLabel(form));
    const body = encodeURIComponent(formToText(form));
    window.location.href = `mailto:${EMAIL_TO}?subject=${subject}&body=${body}`;
  }

  function setInlineStatus(form, message, type) {
    let status = form.querySelector(".rnr-form-message");
    if (!status) {
      status = document.createElement("div");
      status.className = "rnr-form-message";
      form.appendChild(status);
    }
    status.textContent = message;
    status.className = "rnr-form-message " + (type || "");
  }


  function shouldSkipGenericFormHandler(form) {
    if (!form) return false;

    const id = (form.id || "").toLowerCase();
    const className = (form.className || "").toString().toLowerCase();
    const page = (document.body?.dataset?.page || "").toLowerCase();

    // Supabase/auth/dashboard/admin/chat forms must NOT be handled by the generic
    // contact-form fallback, or they can accidentally open the user's email app.
    const skippedIds = [
      "loginform",
      "registerform",
      "bountyform",
      "startmessageform",
      "messagecomposer"
    ];

    if (skippedIds.includes(id)) return true;
    if (page === "auth" || page === "dashboard" || page === "admin") return true;
    if (className.includes("rnr-form") && id === "rnrpopupform") return false;

    // Any form explicitly marked as Supabase-controlled should be skipped.
    if (form.dataset.supabaseForm === "true") return true;
    if (form.closest("[data-supabase-zone='true']")) return true;

    return false;
  }

  async function handleFormSubmit(form, event) {
    if (shouldSkipGenericFormHandler(form)) return;
    event.preventDefault();

    const submit = form.querySelector('button[type="submit"], input[type="submit"]');
    const oldText = submit ? (submit.textContent || submit.value || "Submit") : "";

    if (submit) {
      submit.disabled = true;
      if (submit.tagName === "BUTTON") submit.textContent = "Sending...";
      else submit.value = "Sending...";
    }

    const action = form.getAttribute("action") || FORM_ENDPOINT;

    try {
      if (!isFormspreeConnected(action)) {
        setInlineStatus(form, "Opening your email app with the form details. Add your Formspree ID later for full on-page submissions.", "info");
        setTimeout(() => openMailFallback(form), 350);
        return;
      }

      const response = await fetch(action, {
        method: "POST",
        body: new FormData(form),
        headers: { "Accept": "application/json" }
      });

      if (response.ok) {
        form.reset();
        setInlineStatus(form, "Sent. Rev-N-Rip will review it and follow up.", "success");
      } else {
        setInlineStatus(form, "The form service returned an error. Opening email fallback now.", "error");
        setTimeout(() => openMailFallback(form), 600);
      }
    } catch (error) {
      setInlineStatus(form, "Could not submit through the form service. Opening email fallback now.", "error");
      setTimeout(() => openMailFallback(form), 600);
    } finally {
      setTimeout(() => {
        if (submit) {
          submit.disabled = false;
          if (submit.tagName === "BUTTON") submit.textContent = oldText;
          else submit.value = oldText;
        }
      }, 900);
    }
  }

  function injectStyles() {
    if (document.getElementById("revnrip-popup-styles-final")) return;

    const css = `
      .rnr-form-message{
        margin-top:12px;
        padding:12px 14px;
        border-radius:16px;
        border:1px solid rgba(255,255,255,.10);
        background:rgba(255,255,255,.055);
        color:#ffe4f6;
        font-weight:800;
        line-height:1.45;
      }
      .rnr-form-message.success{background:rgba(90,255,166,.08);border-color:rgba(90,255,166,.22)}
      .rnr-form-message.error{background:rgba(255,90,120,.08);border-color:rgba(255,90,120,.26)}
      .rnr-form-message.info{background:rgba(255,179,77,.08);border-color:rgba(255,179,77,.20)}



      .rnr-pop-overlay{
        position:fixed;
        inset:0;
        z-index:999999;
        display:none;
        align-items:center;
        justify-content:center;
        padding:16px;
        background:
          radial-gradient(circle at 20% 12%, rgba(138,72,255,.16), transparent 28%),
          radial-gradient(circle at 82% 16%, rgba(255,179,77,.10), transparent 24%),
          rgba(5,6,12,.66);
        backdrop-filter:blur(14px);
        font-family:Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
      }
      .rnr-pop-overlay.rnr-show{display:flex;animation:rnrFadeIn .26s ease both}
      .rnr-pop{
        width:min(500px, calc(100% - 20px));
        max-height:88vh;
        overflow:auto;
        position:relative;
        border-radius:26px;
        border:1px solid rgba(255,255,255,.10);
        background:linear-gradient(180deg, rgba(11,9,20,.97), rgba(8,7,16,.95));
        box-shadow:0 28px 90px rgba(0,0,0,.52), 0 0 0 1px rgba(255,255,255,.03) inset;
        color:#fff;
        animation:rnrPopIn .34s cubic-bezier(.2,1.1,.2,1) both;
      }
      .rnr-pop::before{
        content:"";
        position:absolute;
        inset:0;
        border-radius:26px;
        pointer-events:none;
        background:
          linear-gradient(145deg, rgba(255,255,255,.06), transparent 24%),
          radial-gradient(circle at top right, rgba(160,95,255,.10), transparent 30%);
      }
      .rnr-pop-inner{position:relative;z-index:1;display:block}
      .rnr-pop-content{padding:18px}
      .rnr-pop-hero{
        position:relative;
        overflow:hidden;
        border-radius:18px;
        height:190px;
        margin-bottom:16px;
        border:1px solid rgba(255,255,255,.10);
        background:
          linear-gradient(180deg, rgba(0,0,0,.04), rgba(0,0,0,.28)),
          radial-gradient(circle at center, rgba(140,74,255,.24), transparent 42%),
          #0b0a14;
        box-shadow:0 16px 40px rgba(0,0,0,.28);
      }
      .rnr-pop-hero img{
        width:100%;
        height:100%;
        display:block;
        object-fit:cover;
        filter:saturate(1.05) contrast(1.04);
        transform:scale(1.01);
      }
      .rnr-pop-hero::after{
        content:"";
        position:absolute;
        inset:0;
        background:linear-gradient(180deg, rgba(4,4,10,.04), rgba(4,4,10,.12) 50%, rgba(4,4,10,.65));
        pointer-events:none;
      }
      .rnr-badge{
        display:inline-flex;
        align-items:center;
        gap:8px;
        padding:8px 11px;
        border-radius:999px;
        border:1px solid rgba(255,255,255,.10);
        background:rgba(255,255,255,.055);
        color:#ffe4f6;
        font-size:11px;
        font-weight:950;
        letter-spacing:.13em;
        text-transform:uppercase;
      }
      .rnr-logo-row{display:flex;align-items:center;gap:10px;margin:10px 0 8px}
      .rnr-logo-orb{position:relative;width:52px;height:52px;display:grid;place-items:center;flex:0 0 auto}
      .rnr-logo-orb::before{
        content:"";
        position:absolute;
        inset:-8px;
        border-radius:50%;
        background:radial-gradient(circle, rgba(255,47,152,.18), transparent 65%);
        animation:rnrLogoPulse 2.8s ease-in-out infinite;
      }
      .rnr-logo-orb img{
        position:relative;
        max-width:100%;
        max-height:100%;
        object-fit:contain;
        filter:drop-shadow(0 0 14px rgba(255,255,255,.12)) drop-shadow(0 0 10px rgba(255,47,152,.22));
        animation:rnrLogoFloat 3.4s ease-in-out infinite;
      }
      .rnr-logo-label{color:#ffcf8a;font-size:12px;font-weight:900;letter-spacing:.14em;text-transform:uppercase}
      .rnr-pop h2{margin:8px 0 8px;font-size:clamp(26px,4vw,38px);line-height:1.02;letter-spacing:-.03em}
      .rnr-gradient{background:linear-gradient(135deg,#fff,#ecd9ff 40%,#b07cff 70%,#ffcf8a 100%);-webkit-background-clip:text;background-clip:text;color:transparent}
      .rnr-pop p{margin:0;color:#eadff7;line-height:1.5;font-size:14px}
      .rnr-perks{display:grid;gap:8px;margin-top:12px}
      .rnr-perk{display:flex;gap:9px;align-items:flex-start;color:#f1e6f8;font-size:13px}
      .rnr-perk-icon{
        position:relative;
        width:24px;
        height:24px;
        border-radius:8px;
        display:grid;
        place-items:center;
        flex:0 0 auto;
        background:linear-gradient(135deg,#7b33ff,#ff2f98,#ffb34d);
        box-shadow:0 8px 18px rgba(255,47,152,.18), inset 0 1px 0 rgba(255,255,255,.25);
      }
      .rnr-perk-icon::before{
        content:"";
        display:block;
        width:11px;
        height:11px;
        background:#fff;
        opacity:.94;
      }
      .rnr-icon-bolt::before{clip-path:polygon(58% 0,18% 52%,48% 52%,36% 100%,82% 42%,54% 42%)}
      .rnr-icon-gem::before{
        width:12px;
        height:10px;
        clip-path:polygon(50% 0,100% 36%,76% 100%,24% 100%,0 36%);
      }
      .rnr-icon-flag::before{
        width:12px;
        height:12px;
        clip-path:polygon(12% 0,24% 0,24% 100%,12% 100%,12% 0,30% 4%,88% 4%,76% 34%,88% 64%,30% 64%);
      }
      .rnr-form{display:grid;gap:10px;margin-top:14px}
      .rnr-form input{
        width:100%;
        box-sizing:border-box;
        padding:12px 13px;
        border-radius:14px;
        border:1px solid rgba(255,255,255,.12);
        background:rgba(255,255,255,.055);
        color:#fff;
        outline:none;
        font:inherit;
      }
      .rnr-form input::placeholder{color:#cfc0de}
      .rnr-form input:focus{border-color:rgba(255,179,77,.42);box-shadow:0 0 0 4px rgba(255,179,77,.08)}
      .rnr-actions{display:flex;gap:10px;flex-wrap:wrap;margin-top:2px}
      .rnr-submit,.rnr-skip{
        appearance:none;
        border:none;
        cursor:pointer;
        font:inherit;
        font-weight:900;
        border-radius:14px;
        padding:12px 16px;
        transition:transform .16s ease, box-shadow .16s ease, opacity .16s ease;
      }
      .rnr-submit{background:linear-gradient(135deg,#7b33ff,#ff2f98,#ffb34d);color:#fff;box-shadow:0 14px 26px rgba(255,47,152,.24)}
      .rnr-submit:hover,.rnr-skip:hover{transform:translateY(-1px)}
      .rnr-skip{background:rgba(255,255,255,.055);color:#fff;border:1px solid rgba(255,255,255,.10)}
      .rnr-small{margin-top:8px;color:#bbaed0;font-size:12px}
      .rnr-close{
        position:absolute;
        top:10px;
        right:10px;
        width:34px;
        height:34px;
        border-radius:12px;
        border:1px solid rgba(255,255,255,.12);
        background:rgba(10,10,20,.54);
        color:#fff;
        cursor:pointer;
        font-size:20px;
        line-height:1;
        display:grid;
        place-items:center;
        z-index:3;
      }
      .rnr-close:hover{background:rgba(255,255,255,.10)}
      .rnr-form-message{
        margin-top:6px;
        padding:11px 12px;
        border-radius:13px;
        border:1px solid rgba(255,255,255,.10);
        background:rgba(255,255,255,.055);
        color:#ffe4f6;
        font-weight:800;
        line-height:1.45;
      }
      .rnr-form-message.success{background:rgba(90,255,166,.08);border-color:rgba(90,255,166,.22)}
      .rnr-form-message.error{background:rgba(255,90,120,.08);border-color:rgba(255,90,120,.26)}
      .rnr-form-message.info{background:rgba(255,179,77,.08);border-color:rgba(255,179,77,.20)}
      @media (max-width:760px){
        .rnr-pop{width:calc(100% - 12px);max-height:84vh;border-radius:22px}
        .rnr-pop-content{padding:15px}
        .rnr-pop-hero{height:150px;margin-bottom:14px;border-radius:16px}
        .rnr-pop h2{font-size:24px}
      }
      @keyframes rnrFadeIn{from{opacity:0}to{opacity:1}}
      @keyframes rnrPopIn{from{opacity:0;transform:translateY(20px) scale(.94)}to{opacity:1;transform:translateY(0) scale(1)}}
      @keyframes rnrLogoFloat{0%,100%{transform:translateY(0)}50%{transform:translateY(-8px)}}
      @keyframes rnrLogoPulse{0%,100%{transform:scale(1);opacity:.72}50%{transform:scale(1.13);opacity:1}}
      @keyframes rnrGlint{from{transform:rotate(0deg)}to{transform:rotate(360deg)}}
      @media(max-width:760px){
        .rnr-pop-inner{grid-template-columns:1fr}
        .rnr-pop-visual{display:none}
        .rnr-pop-content{padding:28px 22px}
        .rnr-logo-orb{width:68px;height:68px}
        .rnr-actions{display:grid;grid-template-columns:1fr}
        .rnr-submit,.rnr-skip{width:100%}
      }
    `;

    const style = document.createElement("style");
    style.id = "revnrip-popup-styles-final";
    style.textContent = css;
    document.head.appendChild(style);
  }

  function injectPopup() {
    if (document.getElementById("rnrPopupOverlay")) return;

    const wrapper = document.createElement("div");
    wrapper.innerHTML = `
      <div class="rnr-pop-overlay" id="rnrPopupOverlay" aria-hidden="true">
        <div class="rnr-pop" role="dialog" aria-modal="true" aria-labelledby="rnrPopupTitle">
          <button class="rnr-close" type="button" id="rnrPopupClose" aria-label="Close popup">Ã—</button>
          <div class="rnr-pop-inner">
            <div class="rnr-pop-content">
              <div class="rnr-pop-hero"><img src="${POPUP_THEME_IMG}" alt="Luxury Rev-N-Rip vault scene"></div>
              <span class="rnr-badge">Rev-N-Rip Inner Lane</span>
              <div class="rnr-logo-row">
                <div class="rnr-logo-orb"><img src="${LOGO_SRC}" alt="Rev-N-Rip logo"></div>
                <div class="rnr-logo-label">Premium collector access</div>
              </div>
              <h2 id="rnrPopupTitle"><span class="rnr-gradient">Unlock the vault.</span></h2>
              <p>Join the Rev-N-Rip mailing list for future promo codes, drop alerts, bounty updates, and giveaway entry opportunities.</p>
              <div class="rnr-perks">
                <div class="rnr-perk"><span class="rnr-perk-icon rnr-icon-bolt" aria-hidden="true"></span><div>Get first notice on drops, bounty moves, and site updates.</div></div>
                <div class="rnr-perk"><span class="rnr-perk-icon rnr-icon-gem" aria-hidden="true"></span><div>Stay eligible for future giveaways, promo codes, and collector perks.</div></div>
                <div class="rnr-perk"><span class="rnr-perk-icon rnr-icon-flag" aria-hidden="true"></span><div>Keep your foot in the fast lane for PokÃ©mon, MetaZoo, and vault activity.</div></div>
              </div>
              <form class="rnr-form" id="rnrPopupForm" action="${FORM_ENDPOINT}" method="POST">
                <input type="hidden" name="_subject" value="New Rev-N-Rip Mailing List Signup">
                <input type="hidden" name="send_to" value="${EMAIL_TO}">
                <input type="hidden" name="recipient" value="${EMAIL_TO}">
                <input type="hidden" name="form_type" value="Mailing List / Giveaway Signup">
                <input type="text" name="name" placeholder="Name or collector handle">
                <input type="email" name="email" placeholder="Email address" required>
                <div class="rnr-actions">
                  <button class="rnr-submit" type="submit">Join + Enter</button>
                  <button class="rnr-skip" type="button" id="rnrPopupSkip">Not now</button>
                </div>
                <div class="rnr-small">No spam. Just drops, codes, and collector fuel.</div>
              </form>
            </div>
          </div>
        </div>
      </div>`;

    document.body.appendChild(wrapper.firstElementChild);
  }

  function setupPopup() {
    const overlay = document.getElementById("rnrPopupOverlay");
    const closeBtn = document.getElementById("rnrPopupClose");
    const skipBtn = document.getElementById("rnrPopupSkip");
    const form = document.getElementById("rnrPopupForm");

    if (!overlay || !closeBtn || !skipBtn || !form) return;

    function closePopup() {
      overlay.classList.remove("rnr-show");
      overlay.setAttribute("aria-hidden", "true");
    }

    function showPopup() {
      if (sessionStorage.getItem(POPUP_SESSION_KEY)) return;
      setTimeout(function () {
        overlay.classList.add("rnr-show");
        overlay.setAttribute("aria-hidden", "false");
        sessionStorage.setItem(POPUP_SESSION_KEY, "yes");
      }, 700);
    }

    closeBtn.addEventListener("click", closePopup);
    skipBtn.addEventListener("click", closePopup);
    overlay.addEventListener("click", function (event) {
      if (event.target === overlay) closePopup();
    });
    document.addEventListener("keydown", function (event) {
      if (event.key === "Escape" && overlay.classList.contains("rnr-show")) closePopup();
    });
    form.addEventListener("submit", function (event) {
      handleFormSubmit(form, event);
    });

    showPopup();
  }

  function wireForms() {
    document.querySelectorAll("form").forEach(function (form) {
      if (form.id === "rnrPopupForm") return;
      if (shouldSkipGenericFormHandler(form)) return;
      if (form.dataset.revnripWired === "yes") return;
      form.dataset.revnripWired = "yes";

      if (!form.querySelector('input[name="recipient"]')) {
        const recipient = document.createElement("input");
        recipient.type = "hidden";
        recipient.name = "recipient";
        recipient.value = EMAIL_TO;
        form.prepend(recipient);
      }

      if (!form.querySelector('input[name="send_to"]')) {
        const sendTo = document.createElement("input");
        sendTo.type = "hidden";
        sendTo.name = "send_to";
        sendTo.value = EMAIL_TO;
        form.prepend(sendTo);
      }

      form.addEventListener("submit", function (event) {
        handleFormSubmit(form, event);
      });
    });
  }

  function init() {
    injectStyles();
    injectPopup();
    setupPopup();
    wireForms();
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", init);
  } else {
    init();
  }
})();
